def get_es_client():
    """Create and return an Elasticsearch client with connection pooling."""
    kwargs = {
        'hosts': [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
        'max_retries': 3,
        'retry_on_timeout': True,
        'request_timeout': 10,
        'maxsize': 25,  # Connection pool size for high traffic
    }

    if ES_USERNAME and ES_PASSWORD:
        kwargs['basic_auth'] = (ES_USERNAME, ES_PASSWORD)

    return Elasticsearch(**kwargs)


es_client = get_es_client()


def build_search_query(keyword, category=None, min_price=None, max_price=None,
                       in_stock=None, sort_by=None, sort_order='desc'):
    """Build an Elasticsearch query with optional filters."""
    must_clauses = []
    filter_clauses = []

    # Main keyword search with multi-match across relevant fields
    if keyword:
        must_clauses.append({
            'multi_match': {
                'query': keyword,
                'fields': [
                    'name^3',          # Boost product name matches
                    'name.autocomplete^2',
                    'description^1.5',
                    'brand^2',
                    'category^1',
                    'tags^1',
                    'sku^4',           # Exact SKU matches get highest boost
                ],
                'type': 'best_fields',
                'fuzziness': 'AUTO',
                'prefix_length': 2,
                'minimum_should_match': '75%',
            }
        })

    # Category filter
    if category:
        filter_clauses.append({
            'term': {'category.keyword': category}
        })

    # Price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range['gte'] = float(min_price)
        if max_price is not None:
            price_range['lte'] = float(max_price)
        filter_clauses.append({
            'range': {'price': price_range}
        })

    # In-stock filter
    if in_stock is not None:
        filter_clauses.append({
            'term': {'in_stock': in_stock}
        })

    query = {
        'bool': {
            'must': must_clauses if must_clauses else [{'match_all': {}}],
            'filter': filter_clauses,
        }
    }

    # Build sort
    sort = []
    if sort_by:
        valid_sort_fields = ['price', 'created_at', 'rating', 'popularity']
        if sort_by in valid_sort_fields:
            sort.append({sort_by: {'order': sort_order}})

    # Always add _score as secondary sort for relevance
    if not sort_by or sort_by != '_score':
        sort.append({'_score': {'order': 'desc'}})

    return query, sort


