def format_product(hit):
    """Format an Elasticsearch hit into a product response."""
    source = hit.get('_source', {})
    return {
        'id': hit.get('_id'),
        'score': hit.get('_score'),
        'name': source.get('name'),
        'description': source.get('description'),
        'price': source.get('price'),
        'currency': source.get('currency', 'USD'),
        'category': source.get('category'),
        'brand': source.get('brand'),
        'image_url': source.get('image_url'),
        'thumbnail_url': source.get('thumbnail_url'),
        'rating': source.get('rating'),
        'review_count': source.get('review_count'),
        'in_stock': source.get('in_stock'),
        'sku': source.get('sku'),
        'tags': source.get('tags', []),
        'created_at': source.get('created_at'),
        'highlights': hit.get('highlight', {}),
    }


def format_aggregations(aggs):
    """Format Elasticsearch aggregations into a facets response."""
    facets = {}

    if 'categories' in aggs:
        facets['categories'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['categories'].get('buckets', [])
        ]

    if 'brands' in aggs:
        facets['brands'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['brands'].get('buckets', [])
        ]

    if 'price_ranges' in aggs:
        facets['price_ranges'] = [
            {
                'key': bucket['key'],
                'from': bucket.get('from'),
                'to': bucket.get('to'),
                'count': bucket['doc_count'],
            }
            for bucket in aggs['price_ranges'].get('buckets', [])
        ]

    if 'avg_price' in aggs:
        facets['avg_price'] = aggs['avg_price'].get('value')

    if 'in_stock_count' in aggs:
        facets['in_stock_count'] = aggs['in_stock_count'].get('doc_count', 0)

    return facets


@app.route('/api/search', methods=['GET'])
def search_products():
    """
    Search products endpoint.

    Query Parameters:
        q (str): Search keyword (required)
        category (str): Filter by category
        min_price (float): Minimum price filter
        max_price (float): Maximum price filter
        in_stock (bool): Filter by stock availability
        sort_by (str): Sort field (price, created_at, rating, popularity)
        sort_order (str): Sort order (asc, desc) - default: desc
        page (int): Page number (1-based) - default: 1
        page_size (int): Results per page - default: 20, max: 100
        include_facets (bool): Include aggregation facets - default: true

    Returns:
        JSON response with products, pagination info, and optional facets.
    """
    start_time = time.time()

    # Extract and validate query parameters
    keyword = request.args.get('q', '').strip()
    if not keyword:
        return jsonify({
            'error': 'Missing required parameter',
            'message': 'Query parameter "q" is required',
        }), 400

    if len(keyword) > 500:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'Query parameter "q" must be 500 characters or fewer',
        }), 400

    # Pagination
    try:
        page = max(1, int(request.args.get('page', 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        page_size = min(MAX_PAGE_SIZE, max(1, int(request.args.get('page_size', DEFAULT_PAGE_SIZE))))
    except (ValueError, TypeError):
        page_size = DEFAULT_PAGE_SIZE

    # Limit deep pagination to prevent performance issues
    max_offset = 10000
    offset = (page - 1) * page_size
    if offset + page_size > max_offset:
        return jsonify({
            'error': 'Pagination limit exceeded',
            'message': f'Cannot paginate beyond {max_offset} results. Use more specific search terms.',
        }), 400

    # Optional filters
    category = request.args.get('category')
    min_price = request.args.get('min_price')
    max_price = request.args.get('max_price')

    in_stock = request.args.get('in_stock')
    if in_stock is not None:
        in_stock = in_stock.lower() in ('true', '1', 'yes')

    sort_by = request.args.get('sort_by')
    sort_order = request.args.get('sort_order', 'desc')
    if sort_order not in ('asc', 'desc'):
        sort_order = 'desc'

    include_facets = request.args.get('include_facets', 'true').lower() in ('true', '1', 'yes')

    # Validate price parameters
    try:
        if min_price is not None:
            min_price = float(min_price)
            if min_price < 0:
                return jsonify({
                    'error': 'Invalid parameter',
                    'message': 'min_price must be non-negative',
                }), 400
    except ValueError:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'min_price must be a valid number',
        }), 400

    try:
        if max_price is not None:
            max_price = float(max_price)
            if max_price < 0:
                return jsonify({
                    'error': 'Invalid parameter',
                    'message': 'max_price must be non-negative',
                }), 400
    except ValueError:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'max_price must be a valid number',
        }), 400

    if min_price is not None and max_price is not None and min_price > max_price:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'min_price cannot be greater than max_price',
        }), 400

    # Build the query
    query, sort = build_search_query(
        keyword=keyword,
        category=category,
        min_price=min_price,
        max_price=max_price,
        in_stock=in_stock,
        sort_by=sort_by,
        sort_order=sort_order,
    )

    # Build the search body
    search_body = {
        'query': query,
        'sort': sort,
        'from': offset,
        'size': page_size,
        'timeout': SEARCH_TIMEOUT,
        'highlight': {
            'fields': {
                'name': {
                    'number_of_fragments': 1,
                    'fragment_size': 150,
                },
                'description': {
                    'number_of_fragments': 2,
                    'fragment_size': 200,
                },
            },
            'pre_tags': ['<em>'],
            'post_tags': ['</em>'],
        },
        '_source': {
            'includes': [
                'name', 'description', 'price', 'currency', 'category',
                'brand', 'image_url', 'thumbnail_url', 'rating',
                'review_count', 'in_stock', 'sku', 'tags', 'created_at',
            ]
        },
        'suggest': {
            'text': keyword,
            'keyword_suggestion': {
                'term': {
                    'field': 'name',
                    'suggest_mode': 'popular',
                    'min_word_length': 3,
                }
            }
        }
    }

    if include_facets:
        search_body['aggs'] = build_aggregations()

    # Execute search
    try:
        response = es_client.search(
            index=ES_INDEX,
            body=search_body,
            request_timeout=10,
        )
    except Exception as e:
        logger.error(f"Elasticsearch search error: {str(e)}", exc_info=True)
        return jsonify({
            'error': 'Search service unavailable',
            'message': 'Unable to process search request. Please try again later.',
        }), 503

    # Process results
    hits = response.get('hits', {})
    total_hits = hits.get('total', {}).get('value', 0)
    total_relation = hits.get('total', {}).get('relation', 'eq')
    timed_out = response.get('timed_out', False)

    products = [format_product(hit) for hit in hits.get('hits', [])]

    total_pages = (total_hits + page_size - 1) // page_size if total_hits > 0 else 0

    # Build response
    result = {
        'query': keyword,
        'products': products,
        'pagination': {
            'page': page,
            'page_size': page_size,
            'total_results': total_hits,
            'total_results_relation': total_relation,
            'total_pages': total_pages,
            'has_next': page < total_pages,
            'has_previous': page > 1,
        },
        'metadata': {
            'took_ms': response.get('took', 0),
            'timed_out': timed_out,
            'api_time_ms': round((time.time() - start_time) * 1000, 2),
        }
    }

    # Include facets if requested
    if include_facets and 'aggregations' in response:
        result['facets'] = format_aggregations(response['aggregations'])

    # Include suggestions if available
    suggestions = response.get('suggest', {}).get('keyword_suggestion', [])
    if suggestions:
        suggestion_options = []
        for suggestion in suggestions:
            for option in suggestion.get('options', []):
                suggestion_options.append({
                    'text': option.get('text'),
                    'score': option.get('score'),
                    'freq': option.get('freq'),
                })
        if suggestion_options:
            result['suggestions'] = suggestion_options

    logger.info(
        f"Search query='{keyword}' page={page} results={total_hits} "
        f"took={response.get('took', 0)}ms api_time={result['metadata']['api_time_ms']}ms"
    )

    return jsonify(result), 200


